import{_ as e,o as t,c as o,ag as i}from"./chunks/framework.1N8rnUr9.js";const m=JSON.parse('{"title":"Automated & Manual Mapping","description":"","frontmatter":{},"headers":[],"relativePath":"features/product-mapping.md","filePath":"features/product-mapping.md","lastUpdated":null}'),r={name:"features/product-mapping.md"};function n(l,a,p,s,u,d){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="automated-manual-mapping" tabindex="-1">Automated &amp; Manual Mapping <a class="header-anchor" href="#automated-manual-mapping" aria-label="Permalink to &quot;Automated &amp; Manual Mapping&quot;">​</a></h1><p>The core power of TubeBay lies in how it links YouTube content to your WooCommerce products. This process is called <strong>Mapping</strong>.</p><h2 id="manual-mapping" tabindex="-1">Manual Mapping <a class="header-anchor" href="#manual-mapping" aria-label="Permalink to &quot;Manual Mapping&quot;">​</a></h2><p>Manual mapping gives you total control over which video appears on which product page.</p><ol><li>Locate a video in the <a href="/tubebay/features/library-management.html">Library</a>.</li><li>Click the <strong>Map to Product</strong> button.</li><li>In the search modal, type the name or SKU of your product.</li><li>Select the product from the dropdown and click <strong>Save</strong>.</li></ol><h2 id="mapping-rules" tabindex="-1">Mapping Rules <a class="header-anchor" href="#mapping-rules" aria-label="Permalink to &quot;Mapping Rules&quot;">​</a></h2><ul><li><strong>One Video, One Product:</strong> Each video can be mapped to one product (in the Free version).</li><li><strong>One Product, One Video:</strong> Each product can have one primary TubeBay video displayed at a time.</li><li><strong>Persistent Links:</strong> Once a video is mapped, the link remains until you manually unmap it or delete the product.</li></ul><h2 id="product-search" tabindex="-1">Product Search <a class="header-anchor" href="#product-search" aria-label="Permalink to &quot;Product Search&quot;">​</a></h2><p>The mapping search bar utilizes the WooCommerce product search API, allowing you to find products by:</p><ul><li>Title</li><li>SKU</li><li>ID</li></ul><h2 id="automated-suggestions-pro" tabindex="-1">Automated Suggestions (Pro) <a class="header-anchor" href="#automated-suggestions-pro" aria-label="Permalink to &quot;Automated Suggestions (Pro)&quot;">​</a></h2><p>The Pro version of TubeBay includes smart mapping features that can automatically suggest or link videos to products based on:</p><ul><li>Matching YouTube video titles to WooCommerce product names.</li><li>Extracting SKUs from video descriptions.</li><li>Mapping entire YouTube playlists to specific WooCommerce categories.</li></ul>',13)])])}const h=e(r,[["render",n]]);export{m as __pageData,h as default};
